import React from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useTheme } from '../context/ThemeContext';
import ThemeToggle from './ThemeToggle';
import { 
  Cpu, 
  LayoutDashboard, 
  TrendingUp, 
  LogOut, 
  ShieldCheck,
  Terminal,
  User
} from 'lucide-react';

const Navbar = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();
  
  /* 🎯 ESLint Fix: We only call useTheme() to trigger the context, 
     without assigning 'theme' to a variable since we use CSS variables instead. */
  useTheme();

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  const isActive = (path) => location.pathname === path;

  // 📐 Institutional Layout Styles
  const styles = {
    nav: { 
      position: 'sticky', 
      top: '15px', 
      zIndex: 100, 
      margin: '0 auto',
      width: '95%', 
      maxWidth: '1200px',
      backgroundColor: 'var(--surface-glass)', 
      borderRadius: '20px',
      padding: '0.6rem 1.5rem',
      border: '1px solid var(--surface-border)', 
      boxShadow: 'var(--shadow-elevated)',
      backdropFilter: 'blur(18px)',
      display: 'flex',
      justifyContent: 'center',
      transition: 'all 0.3s ease'
    },
    container: { 
      display: 'flex', 
      justifyContent: 'space-between', 
      alignItems: 'center',
      width: '100%'
    },
    logo: { 
      fontSize: '1.1rem', 
      color: 'var(--text-primary)', 
      textDecoration: 'none', 
      display: 'flex', 
      alignItems: 'center', 
      gap: '10px',
      fontWeight: 'bold',
      letterSpacing: '0.15em',
      textTransform: 'uppercase'
    },
    navLinks: { display: 'flex', alignItems: 'center', gap: '0.5rem' },
    
    // ⚡ Active Node Logic: Cyber Purple highlight matching your theme tokens
    link: (active) => ({
      textDecoration: 'none',
      fontWeight: '700',
      fontSize: '10px',
      padding: '0.5rem 1rem',
      borderRadius: '10px',
      display: 'flex', 
      alignItems: 'center', 
      gap: '8px',
      transition: 'all 0.3s ease',
      backgroundColor: active ? 'var(--accent-glow)' : 'transparent',
      color: active ? 'var(--accent-primary)' : 'var(--text-secondary)',
      border: active ? '1px solid var(--accent-primary)' : '1px solid transparent',
      textTransform: 'uppercase',
      letterSpacing: '0.1em'
    }),
    
    logoutBtn: { 
      backgroundColor: 'rgba(239, 68, 68, 0.1)', 
      color: '#ef4444', 
      border: '1px solid rgba(239, 68, 68, 0.15)',
      padding: '0.5rem 0.8rem', 
      borderRadius: '10px', 
      cursor: 'pointer', 
      display: 'flex', 
      alignItems: 'center',
      transition: 'all 0.2s ease',
      marginLeft: '0.5rem'
    }
  };

  return (
    <nav style={styles.nav} className="reveal-data">
      <div style={styles.container}>
        {/* Brand Node */}
        <Link to="/" style={styles.logo}>
          <div className="p-1.5 bg-[var(--accent-glow)] rounded-lg shadow-[0_0_10px_var(--accent-glow)]">
            <Cpu size={20} className="text-[var(--accent-primary)]" />
          </div>
          <span className="hidden sm:inline tracking-widest">Finify AI</span>
        </Link>

        {/* Action Hub */}
        <div style={styles.navLinks}>
          <ThemeToggle />
          
          {user ? (
            <>
              <Link to="/dashboard" style={styles.link(isActive('/dashboard'))}>
                <LayoutDashboard size={14} /> Dashboard
              </Link>
              <Link to="/generate" style={styles.link(isActive('/generate'))}>
                <TrendingUp size={14} /> Strategy
              </Link>
              <Link to="/profile" style={styles.link(isActive('/profile'))}>
                <User size={14} /> Node
              </Link>
              <button onClick={handleLogout} style={styles.logoutBtn} title="Terminate Session">
                <LogOut size={14} />
              </button>
            </>
          ) : (
            <>
              <Link to="/login" style={styles.link(isActive('/login'))}>
                <Terminal size={14} /> Access
              </Link>
              <Link 
                to="/register" 
                style={{
                  ...styles.link(true), 
                  backgroundImage: 'linear-gradient(135deg, var(--accent-secondary), var(--accent-primary))', 
                  color: '#ffffff',
                  border: 'none',
                  boxShadow: '0 0 10px var(--accent-glow)'
                }}
              >
                <ShieldCheck size={14} /> Initialize
              </Link>
            </>
          )}
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
